import React from 'react';

function ProcessStatus() {
  return (
    <div className="relative overflow-hidden bg-gray-900 border border-purple-500 rounded-xl p-6 shadow-lg h-full">
      {/* ✨ Shine Animation */}
      <div
        className="absolute top-[-50%] left-[-75%] w-1/2 h-[200%] bg-gradient-to-r from-transparent via-white/30 to-transparent
        animate-shineMove pointer-events-none z-10"
        style={{ transform: 'skewX(-40deg)' }}
      />

      {/* Heading */}
      <h3 className="text-xl font-semibold text-purple-400 mb-4 relative z-20">How It Works</h3>

      {/* List with smaller font */}
      <ol className="space-y-1 text-sm text-gray-300 list-decimal list-inside relative z-20 leading-relaxed">
        <li>Select a text or audio file</li>
        <li>Click on <strong>"Generate Summary"</strong></li>
        <li>Review transcript & AI summary</li>
        <li>Now you can copy, download and send it via email</li>
        <li>
          When you're redirected to this webpage via Zoom extension, click on
          <strong> "Generate Zoom Meeting Summary" </strong> for summary
        </li>
      </ol>
    </div>
  );
}

export default ProcessStatus;
